def valid_path(n, edges, source, destination):
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v); graph[v].append(u)
    queue, seen = deque([source]), {source}
    while queue:
        node = queue.popleft()
        if node == destination: return True
